count_active_reps:
var count = 0;
if (args != null && size(args) >= 2) {
  var reps = args[0];
  var litigantId = "" + args[1];
  if (reps != null) {
    for (var rep : reps) {
      if (rep != null && rep.isActive == true) {
        var representing = rep.representing;
        if (representing != null) {
          for (var r : representing) {
            if (r != null && litigantId == ("" + r.individualId)) {
              count++;
              break;
            }
          }
        }
      }
    }
  }
}
return count;

range_lookup:
