if (ranges != null) {
  for (var r : ranges) {
    if (r != null && value >= (r.min * 1.0) && value <= (r.max * 1.0)) {
      return r.fee * 1.0;
    }
  }
}
return 0.0;

has_any_advocate:
if (args == null || size(args) < 2) return false;
var litigants = args[0];
var reps = args[1];
if (litigants != null && reps != null) {
  for (var lit : litigants) {
    if (lit != null) {
      var litId = "" + lit.individualId;
      var count = 0;
      for (var rep : reps) {
        if (rep != null && rep.isActive == true) {
          var representing = rep.representing;
          if (representing != null) {
            for (var r : representing) {
              if (r != null && litId == ("" + r.individualId)) {
                count++;
                break;
              }
            }
          }
        }
      }
      if (count > 0) return true;
    }
  }
}
return false;

sum_advocate_range_fee:
if (args == null || size(args) < 3) return 0.0;
var litigants = args[0];
var reps = args[1];
var ranges = args[2];
var total = 0.0;
if (litigants != null && reps != null && ranges != null) {
  for (var lit : litigants) {
    if (lit != null) {
      var litId = "" + lit.individualId;
      var advCount = 0;
      for (var rep : reps) {
        if (rep != null && rep.isActive == true) {
          var representing = rep.representing;
          if (representing != null) {
            for (var r : representing) {
              if (r != null && litId == ("" + r.individualId)) {
                advCount++;
                break;
              }
            }
          }
        }
      }
      var fee = 0.0;
      for (var r : ranges) {
        if (r != null && advCount >= (r.min * 1.0) && advCount <= (r.max * 1.0)) {
          fee = r.fee * 1.0;
          break;
        }
      }
      total = total + fee;
    }
  }
}
return total;
